class Solution {
public:
    int peek(vector<pair<int, int>>& heap) {
        return heap[0].first;
    }

    int dequeue(vector<pair<int, int>>& heap) {
        if (heap.size() == 0) return -1;

        int top = heap[0].first;
        heap.erase(heap.begin());

        for (int i = 1; i < heap.size(); i++) {
            int parent = (i - 1) / 2;
            if (i > heap.size()) continue;
            if (heap[parent].first > heap[i].first) {
                swap(heap[parent], heap[i]);
            }
        }

        return top;
    }

    void heapInsert(vector<pair<int, int>>& heap, int data) {
        heap.push_back(make_pair(data, 0));

        int index = heap.size() - 1;
        while (index > 0) {
            int parent = (index - 1) / 2;
            if (heap[parent].first >= heap[index].first) break;
            swap(heap[parent], heap[index]);
            index = parent;
        }
    }
}

