class Solution:
    def peek(self, heap):
        return heap[0][0]

    def dequeue(self, heap):
        if not heap:
            return -1

        top = heap[0]
        heap.pop(0)

        n = len(heap)
        for i in range(1, n):
            parent = (i - 1) // 2
            if i > n: continue
            if heap[parent][0] > heap[i][0]: heap[parent], heap[i] = heap[i], heap[parent]

        return top[0]

    def heapInsert(self, heap, data):
        heap.append((data, 0))

        n = len(heap)
        index = n - 1
        while index > 0:
            parent = (index - 1) // 2
            if heap[parent][0] >= heap[index][0]: break
            heap[parent], heap[index] = heap[index], heap[parent]
            index = parent

    def solve(self, elements):
        n = len(elements)

        for i in range(n):
            self.heapInsert([], elements[i][0])

        topElement = self.peek([])

        for i in range(n):
            topElement = self.dequeue([])

        self.heapInsert([], elements[i][0])

        return topElement

